								(
									bh_exmnt_iem_id
									, bh_exmnt_id
									, bh_exmnt_iem_nm
									, creator_id
									, created_dt
									, updater_id
									, updated_dt
								)
						values	(
									#{bhExmntIemId}
									, #{bhExmntId}
									, #{bhExmntIemNm}
									, #{creatorId}
									, #{createdDt}
									, #{updaterId}
									, #{updatedDt}
								)

mapper.update:
/** UsptStdrBhExmntIemDao.update */
update uspt_stdr_bh_exmnt_iem
set
	updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
	, bh_exmnt_iem_nm = #{bhExmntIemNm}
where
